// High-Performance Cryptographic Engine - Interview Demonstration Purpose
#include <openssl/evp.h>
#include <openssl/aes.h>
#include <iostream>
#include <vector>

class EncryptionEngine {
public:
    // Utilizing AES-256-GCM for authenticated encryption
    int encrypt_file(const unsigned char* plaintext, int plaintext_len, 
                     unsigned char* key, unsigned char* iv, 
                     unsigned char* ciphertext, unsigned char* tag) {
        EVP_CIPHER_CTX *ctx;
        int len;
        int ciphertext_len;

        if(!(ctx = EVP_CIPHER_CTX_new())) return -1;

        // Initialize encryption operation with AES-256-GCM
        if(1 != EVP_EncryptInit_ex(ctx, EVP_aes_256_gcm(), NULL, NULL, NULL)) return -1;

        // Set IV length (12 bytes is standard for GCM)
